INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('be', 'op', 11, 'OP', '是；存在；处于某种状态', 'exist or have a stated identity or condition', 'The water will be warm in a minute.', '水一会儿就会变暖。', '[{"w":"take","def":"take: 相关的动作或关系词","vs":"与 be 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"take\" / \"be\" 的替换练习"},{"w":"do","def":"do: 可帮助扩展句型的基础词","vs":"与 be 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"do\" / \"be\" 的替换练习"},{"w":"have","def":"have: 同一组 Basic English 操作词","vs":"与 be 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"have\" / \"be\" 的替换练习"}]'),
  ('do', 'op', 12, 'OP', '做；执行；完成', 'perform an action or complete work', 'Do the work before you go out to play.', '出去玩之前先把工作做完。', '[{"w":"be","def":"be: 相关的动作或关系词","vs":"与 do 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"be\" / \"do\" 的替换练习"},{"w":"have","def":"have: 可帮助扩展句型的基础词","vs":"与 do 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"have\" / \"do\" 的替换练习"},{"w":"say","def":"say: 同一组 Basic English 操作词","vs":"与 do 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"say\" / \"do\" 的替换练习"}]'),
  ('have', 'op', 13, 'OP', '有；拥有；经历', 'own, hold, or experience something', 'We have enough time for one more question.', '我们还有足够时间再问一个问题。', '[{"w":"do","def":"do: 相关的动作或关系词","vs":"与 have 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"do\" / \"have\" 的替换练习"},{"w":"say","def":"say: 可帮助扩展句型的基础词","vs":"与 have 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"say\" / \"have\" 的替换练习"},{"w":"see","def":"see: 同一组 Basic English 操作词","vs":"与 have 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"see\" / \"have\" 的替换练习"}]'),
  ('say', 'op', 14, 'OP', '说；表达；写明', 'express words or give a message', 'Say the word slowly and then write it down.', '慢慢说出这个词，然后把它写下来。', '[{"w":"have","def":"have: 相关的动作或关系词","vs":"与 say 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"have\" / \"say\" 的替换练习"},{"w":"see","def":"see: 可帮助扩展句型的基础词","vs":"与 say 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"see\" / \"say\" 的替换练习"},{"w":"send","def":"send: 同一组 Basic English 操作词","vs":"与 say 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"send\" / \"say\" 的替换练习"}]'),
  ('see', 'op', 15, 'OP', '看见；理解；会见', 'notice with the eyes or understand an idea', 'I can see the ship from the window.', '我能从窗户看到那艘船。', '[{"w":"say","def":"say: 相关的动作或关系词","vs":"与 see 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"say\" / \"see\" 的替换练习"},{"w":"send","def":"send: 可帮助扩展句型的基础词","vs":"与 see 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"send\" / \"see\" 的替换练习"},{"w":"may","def":"may: 同一组 Basic English 操作词","vs":"与 see 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"may\" / \"see\" 的替换练习"}]');
